#!/bin/bash
set -e
mkdir -p src/bot src/chain

python3 -c "import base64; open('src/chain/client.ts', 'w').write(base64.b64decode('').decode())"
echo "✓ src/chain/client.ts"
python3 -c "import base64; open('src/chain/pools.ts', 'w').write(base64.b64decode('').decode())"
echo "✓ src/chain/pools.ts"
python3 -c "import base64; open('src/chain/transactions.ts', 'w').write(base64.b64decode('').decode())"
echo "✓ src/chain/transactions.ts"
python3 -c "import base64; open('src/bot/keyboards.ts', 'w').write(base64.b64decode('').decode())"
echo "✓ src/bot/keyboards.ts"
python3 -c "import base64; open('src/bot/commands.ts', 'w').write(base64.b64decode('').decode())"
echo "✓ src/bot/commands.ts"
python3 -c "import base64; open('src/index.ts', 'w').write(base64.b64decode('').decode())"
echo "✓ src/index.ts"
echo ""
echo "✅ All files written!"